process.env.INPUTS_FILE = inputsFile;
process.env.TODOS_FILE = todosFile;
process.env.GENERAL_DB_FILE = generalDbFile;
import { join } from "node:path";
import { tmpdir } from "node:os";
import request from "supertest";

const assert = (condition: unknown, message: string): void => {
  if (!condition) {
    throw new Error(message);
  }
};

const tempDir = await mkdtemp(join(tmpdir(), "quick-input-nest-rxdb-e2e-"));
const filePath = join(tempDir, "inputs.txt");

process.env.INPUTS_FILE = filePath;

const [{ bootstrap }] = await Promise.all([import("../src/server/main")]);

await writeFile(filePath, "", "utf-8");

const app = await bootstrap({ host: "127.0.0.1", port: 3301 });

try {
  const root = await request(app.getHttpServer()).get("/");
  assert(root.status === 200, `Expected root route to succeed, got ${root.status}`);
  assert(root.text.includes("<div id=\"root\"></div>"), "Expected built client index.html");

  const add = await request(app.getHttpServer()).post("/api/inputs/add").send({ text: "nest-rxdb-e2e-entry" });
  assert(add.status === 201 || add.status === 200, `Expected add to succeed, got ${add.status}`);

  const list = await request(app.getHttpServer()).get("/api/inputs/list");
  assert(list.status === 200, `Expected list to succeed, got ${list.status}`);
  assert(Array.isArray(list.body), "Expected list response body to be an array");
  assert(list.body.some((entry: { text: string }) => entry.text === "nest-rxdb-e2e-entry"), "Expected created entry in list output");

  const created = list.body.find((entry: { text: string }) => entry.text === "nest-rxdb-e2e-entry") as { index: number } | undefined;
  if (!created) {
    throw new Error("Expected to locate the inserted entry for cleanup");
  }

  const remove = await request(app.getHttpServer()).post("/api/inputs/delete").send({ index: created.index });
  assert(remove.status === 201 || remove.status === 200, `Expected delete to succeed, got ${remove.status}`);

  console.log("E2E test passed");
} finally {
  await app.close();
  await rm(tempDir, { recursive: true, force: true });
}

import { mkdtemp, rm, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import request from "supertest";

const assert = (condition: unknown, message: string): void => {
  if (!condition) {
    throw new Error(message);
  }
};

const tempDir = await mkdtemp(join(tmpdir(), "quick-input-nest-rxdb-e2e-"));
const inputsFile = join(tempDir, "inputs.txt");
const todosFile = join(tempDir, "todo.json");
const generalDbFile = join(tempDir, "general_db.json");

process.env.INPUTS_FILE = inputsFile;
process.env.TODOS_FILE = todosFile;
process.env.GENERAL_DB_FILE = generalDbFile;

const [{ bootstrap }] = await Promise.all([import("../src/server/main")]);

await writeFile(inputsFile, "", "utf-8");
await writeFile(todosFile, "[]\n", "utf-8");
await writeFile(generalDbFile, '{"notes":[],"bookmarks":[],"contacts":[]}\n', "utf-8");

const app = await bootstrap({ host: "127.0.0.1", port: 3301 });

try {
  const root = await request(app.getHttpServer()).get("/");
  assert(root.status === 200, `Expected root route to succeed, got ${root.status}`);
  assert(root.text.includes("<div id=\"root\"></div>"), "Expected built client index.html");

  const add = await request(app.getHttpServer()).post("/api/inputs/add").send({ text: "nest-rxdb-e2e-entry" });
  assert(add.status === 201 || add.status === 200, `Expected add to succeed, got ${add.status}`);

  const list = await request(app.getHttpServer()).get("/api/inputs/list");
  assert(list.status === 200, `Expected list to succeed, got ${list.status}`);
  assert(Array.isArray(list.body), "Expected list response body to be an array");
  assert(list.body.some((entry: { text: string }) => entry.text === "nest-rxdb-e2e-entry"), "Expected created entry in list output");

  const created = list.body.find((entry: { text: string }) => entry.text === "nest-rxdb-e2e-entry") as { index: number } | undefined;
  if (!created) {
    throw new Error("Expected to locate the inserted entry for cleanup");
  }

  const remove = await request(app.getHttpServer()).post("/api/inputs/delete").send({ index: created.index });
  assert(remove.status === 201 || remove.status === 200, `Expected delete to succeed, got ${remove.status}`);

  const createTodo = await request(app.getHttpServer())
    .post("/api/todos/create")
    .send({ title: "Write docs", details: "Document sync sources", state: "Created" });
  assert(createTodo.status === 201 || createTodo.status === 200, `Expected todo create to succeed, got ${createTodo.status}`);
  const todoId = createTodo.body.id as string | undefined;
  assert(Boolean(todoId), "Expected created todo id");

  const updateTodo = await request(app.getHttpServer())
    .post("/api/todos/update")
    .send({ id: todoId, title: "Write docs", details: "Document sync sources", state: "Done" });
  assert(updateTodo.status === 201 || updateTodo.status === 200, `Expected todo update to succeed, got ${updateTodo.status}`);

  const todoList = await request(app.getHttpServer()).get("/api/todos/list");
  assert(todoList.status === 200, `Expected todo list to succeed, got ${todoList.status}`);
  assert(todoList.body.some((todo: { id: string; state: string }) => todo.id === todoId && todo.state === "Done"), "Expected updated todo in list output");

  const deleteTodo = await request(app.getHttpServer()).post("/api/todos/delete").send({ id: todoId });
  assert(deleteTodo.status === 201 || deleteTodo.status === 200, `Expected todo delete to succeed, got ${deleteTodo.status}`);

  const createNote = await request(app.getHttpServer())
    .post("/api/notes/create")
    .send({ name: "Demo note", body: "Shared general db", color: "green" });
  assert(createNote.status === 201 || createNote.status === 200, `Expected note create to succeed, got ${createNote.status}`);

  const createBookmark = await request(app.getHttpServer())
    .post("/api/bookmarks/create")
    .send({ name: "Solid", url: "https://www.solidjs.com", category: "Framework" });
  assert(createBookmark.status === 201 || createBookmark.status === 200, `Expected bookmark create to succeed, got ${createBookmark.status}`);

  const createContact = await request(app.getHttpServer())
    .post("/api/contacts/create")
    .send({ name: "Support", email: "support@example.com", company: "Acme" });
  assert(createContact.status === 201 || createContact.status === 200, `Expected contact create to succeed, got ${createContact.status}`);

  const notesList = await request(app.getHttpServer()).get("/api/notes/list");
  const bookmarksList = await request(app.getHttpServer()).get("/api/bookmarks/list");
  const contactsList = await request(app.getHttpServer()).get("/api/contacts/list");
  assert(notesList.body.length === 1, "Expected one note in shared general_db source");
  assert(bookmarksList.body.length === 1, "Expected one bookmark in shared general_db source");
  assert(contactsList.body.length === 1, "Expected one contact in shared general_db source");

  console.log("E2E test passed");
} finally {
  await app.close();
  await rm(tempDir, { recursive: true, force: true });
}

const inputsFile = join(tempDir, "inputs.txt");
const todosFile = join(tempDir, "todo.json");
const generalDbFile = join(tempDir, "general_db.json");
import { join } from "node:path";
import { tmpdir } from "node:os";
import { InputsController } from "../src/server/inputs/inputs.controller";
import { InputStorageService } from "../src/server/inputs/input-storage.service";

const assert = (condition: unknown, message: string): void => {
  if (!condition) {
    throw new Error(message);
  }
};

const tempDir = await mkdtemp(join(tmpdir(), "quick-input-nest-rxdb-"));
const filePath = join(tempDir, "inputs.txt");

try {
  const storage = new InputStorageService(filePath, 10);
  const controller = new InputsController(storage);

  await controller.add({ text: "  first  " });
  await controller.add({ text: "   " });
  await controller.add({ text: "second" });

  let entries = await controller.list();
  assert(entries.length === 2, `Expected 2 entries, received ${entries.length}`);
  assert(entries[0]?.text === "second", "Newest entry should be first");
  assert(entries[1]?.text === "first", "Trimmed text should be persisted");

  await controller.delete({ index: 0 });
  entries = await controller.list();
  assert(entries.length === 1, `Expected 1 entry after deletion, received ${entries.length}`);
  assert(entries[0]?.text === "second", "Deleting absolute index 0 should keep the second row");

  const raw = await readFile(filePath, "utf-8");
  assert(raw === "second\n", `Unexpected file contents: ${JSON.stringify(raw)}`);

  let notFound = false;
  try {
    await controller.delete({ index: 9 });
  } catch {
    notFound = true;
  }
  assert(notFound, "Expected missing delete to throw");

  console.log("Smoke test passed");
} finally {
  await rm(tempDir, { recursive: true, force: true });
}

import { mkdtemp, readFile, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { BookmarksController } from "../src/server/general-db/bookmarks.controller";
import { ContactsController } from "../src/server/general-db/contacts.controller";
import { GeneralDbService } from "../src/server/general-db/general-db.service";
import { NotesController } from "../src/server/general-db/notes.controller";
import { InputsController } from "../src/server/inputs/inputs.controller";
import { InputStorageService } from "../src/server/inputs/input-storage.service";
import { TodosController } from "../src/server/todos/todos.controller";
import { TodosService } from "../src/server/todos/todos.service";

const assert = (condition: unknown, message: string): void => {
  if (!condition) {
    throw new Error(message);
  }
};

const tempDir = await mkdtemp(join(tmpdir(), "quick-input-nest-rxdb-"));
const inputsFile = join(tempDir, "inputs.txt");
const todosFile = join(tempDir, "todo.json");
const generalDbFile = join(tempDir, "general_db.json");

try {
  const inputStorage = new InputStorageService(inputsFile, 10);
  const inputs = new InputsController(inputStorage);
  const todos = new TodosController(new TodosService(todosFile));
  const generalDb = new GeneralDbService(generalDbFile);
  const notes = new NotesController(generalDb);
  const bookmarks = new BookmarksController(generalDb);
  const contacts = new ContactsController(generalDb);

  await inputs.add({ text: "  first  " });
  await inputs.add({ text: "   " });
  await inputs.add({ text: "second" });

  let entries = await inputs.list();
  assert(entries.length === 2, `Expected 2 entries, received ${entries.length}`);
  assert(entries[0]?.text === "second", "Newest entry should be first");
  assert(entries[1]?.text === "first", "Trimmed text should be persisted");

  await inputs.delete({ index: 0 });
  entries = await inputs.list();
  assert(entries.length === 1, `Expected 1 entry after deletion, received ${entries.length}`);
  assert(entries[0]?.text === "second", "Deleting absolute index 0 should keep the second row");

  const raw = await readFile(inputsFile, "utf-8");
  assert(raw === "second\n", `Unexpected file contents: ${JSON.stringify(raw)}`);

  let notFound = false;
  try {
    await inputs.delete({ index: 9 });
  } catch {
    notFound = true;
  }
  assert(notFound, "Expected missing delete to throw");

  const createdTodo = await todos.create({ title: "Ship PWA", details: "Make offline first work", state: "Created" });
  const updatedTodo = await todos.update({ id: createdTodo.id, title: "Ship PWA", details: "Wire service worker later", state: "InProgress" });
  assert(updatedTodo.state === "InProgress", "Todo update should change state");
  assert((await todos.list()).length === 1, "Expected a todo to be listed");
  await todos.delete({ id: createdTodo.id });
  assert((await todos.list()).length === 0, "Expected todo deletion to empty the list");

  const createdNote = await notes.create({ name: "Idea", body: "Use one shared json file", color: "violet" });
  const updatedNote = await notes.update({ id: createdNote.id, name: "Idea", body: "Updated body", color: "violet" });
  assert(updatedNote.body === "Updated body", "Note update should persist");
  await notes.delete({ id: createdNote.id });
  assert((await notes.list()).length === 0, "Expected note deletion to empty the list");

  const createdBookmark = await bookmarks.create({ name: "RxDB", url: "https://rxdb.info", category: "Docs" });
  const updatedBookmark = await bookmarks.update({ id: createdBookmark.id, name: "RxDB Docs", url: "https://rxdb.info", category: "Docs" });
  assert(updatedBookmark.name === "RxDB Docs", "Bookmark update should persist");
  await bookmarks.delete({ id: createdBookmark.id });
  assert((await bookmarks.list()).length === 0, "Expected bookmark deletion to empty the list");

  const createdContact = await contacts.create({ name: "Vilius", email: "vilius@example.com", company: "Label Printer" });
  const updatedContact = await contacts.update({ id: createdContact.id, name: "Vilius L.", email: "vilius@example.com", company: "Label Printer" });
  assert(updatedContact.name === "Vilius L.", "Contact update should persist");
  await contacts.delete({ id: createdContact.id });
  assert((await contacts.list()).length === 0, "Expected contact deletion to empty the list");

  console.log("Smoke test passed");
} finally {
  await rm(tempDir, { recursive: true, force: true });
}

import {
  addInputBodySchema,
  bookmarkListSchema,
  contactListSchema,
  createBookmarkBodySchema,
  createContactBodySchema,
  createNoteBodySchema,
  createTodoBodySchema,
  deleteByIdBodySchema,
  deleteInputBodySchema,
  errorResponseSchema,
  inputListSchema,
  noteListSchema,
  okResponseSchema,
  todoListSchema,
  updateBookmarkBodySchema,
  updateContactBodySchema,
  updateNoteBodySchema,
  updateTodoBodySchema,
  type AddInputBody,
  type BookmarkItem,
  type ContactItem,
  type CreateBookmarkBody,
  type CreateContactBody,
  type CreateNoteBody,
  type CreateTodoBody,
  type DeleteByIdBody,
  type DeleteInputBody,
  type InputItem,
  type NoteItem,
  type TodoItem,
  type UpdateBookmarkBody,
  type UpdateContactBody,
  type UpdateNoteBody,
  type UpdateTodoBody,
} from "../shared/contracts";

const readErrorMessage = async (response: Response): Promise<string> => {
  try {
    const body = await response.json();
    const parsed = errorResponseSchema.safeParse(body);
    if (parsed.success) {
      return parsed.data.message;
    }
  } catch {
    // ignore malformed JSON error bodies
  }

  return response.statusText || "Request failed";
};

const expectOk = async (response: Response) => {
  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }

  return okResponseSchema.parse(await response.json());
};

export async function listInputs(): Promise<InputItem[]> {
  const response = await fetch("/api/inputs/list");
  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }

  return inputListSchema.parse(await response.json());
}

export async function addInput(body: AddInputBody): Promise<void> {
  const parsed = addInputBodySchema.parse(body);
  const response = await fetch("/api/inputs/add", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(parsed),
  });

  await expectOk(response);
}

export async function deleteInput(body: DeleteInputBody): Promise<void> {
  const parsed = deleteInputBodySchema.parse(body);
  const response = await fetch("/api/inputs/delete", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(parsed),
  });

  await expectOk(response);
}

const getJson = async <T>(url: string, parser: { parse: (value: unknown) => T }): Promise<T> => {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }
  return parser.parse(await response.json());
};

const postJson = async <TBody, TResult>(
  url: string,
  body: TBody,
  parser: { parse: (value: unknown) => TResult },
): Promise<TResult> => {
  const response = await fetch(url, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!response.ok) {
    throw new Error(await readErrorMessage(response));
  }
  return parser.parse(await response.json());
};

export const listTodos = async (): Promise<TodoItem[]> => getJson("/api/todos/list", todoListSchema);
export const createTodo = async (body: CreateTodoBody): Promise<TodoItem> =>
  postJson("/api/todos/create", createTodoBodySchema.parse(body), createTodoBodySchema.merge(todoListSchema.element));
export const updateTodo = async (body: UpdateTodoBody): Promise<TodoItem> =>
  postJson("/api/todos/update", updateTodoBodySchema.parse(body), todoListSchema.element);
export const deleteTodo = async (body: DeleteByIdBody): Promise<void> => {
  await postJson("/api/todos/delete", deleteByIdBodySchema.parse(body), okResponseSchema);
};

export const listNotes = async (): Promise<NoteItem[]> => getJson("/api/notes/list", noteListSchema);
export const createNote = async (body: CreateNoteBody): Promise<NoteItem> =>
  postJson("/api/notes/create", createNoteBodySchema.parse(body), noteListSchema.element);
export const updateNote = async (body: UpdateNoteBody): Promise<NoteItem> =>
  postJson("/api/notes/update", updateNoteBodySchema.parse(body), noteListSchema.element);
export const deleteNote = async (body: DeleteByIdBody): Promise<void> => {
  await postJson("/api/notes/delete", deleteByIdBodySchema.parse(body), okResponseSchema);
};

export const listBookmarks = async (): Promise<BookmarkItem[]> =>
  getJson("/api/bookmarks/list", bookmarkListSchema);
export const createBookmark = async (body: CreateBookmarkBody): Promise<BookmarkItem> =>
  postJson("/api/bookmarks/create", createBookmarkBodySchema.parse(body), bookmarkListSchema.element);
export const updateBookmark = async (body: UpdateBookmarkBody): Promise<BookmarkItem> =>
  postJson("/api/bookmarks/update", updateBookmarkBodySchema.parse(body), bookmarkListSchema.element);
export const deleteBookmark = async (body: DeleteByIdBody): Promise<void> => {
  await postJson("/api/bookmarks/delete", deleteByIdBodySchema.parse(body), okResponseSchema);
};

export const listContacts = async (): Promise<ContactItem[]> => getJson("/api/contacts/list", contactListSchema);
export const createContact = async (body: CreateContactBody): Promise<ContactItem> =>
  postJson("/api/contacts/create", createContactBodySchema.parse(body), contactListSchema.element);
export const updateContact = async (body: UpdateContactBody): Promise<ContactItem> =>
  postJson("/api/contacts/update", updateContactBodySchema.parse(body), contactListSchema.element);
export const deleteContact = async (body: DeleteByIdBody): Promise<void> => {
  await postJson("/api/contacts/delete", deleteByIdBodySchema.parse(body), okResponseSchema);
